output.output:
{
  "config": {
    "view": {
      "continuousWidth": 300,
      "continuousHeight": 300
    }
  },
  "vconcat": [
    {
      "mark": {
        "type": "point"
      },
      "encoding": {
        "color": {
          "condition": {
            "param": "brush",
            "field": "Major_Genre",
            "type": "nominal"
          },
          "value": "lightgray"
        },
        "x": {
          "field": "IMDB_Rating",
          "title": "IMDB Rating",
          "type": "quantitative"
        },
        "y": {
          "field": "Rotten_Tomatoes_Rating",
          "title": "Rotten Tomatoes Rating",
          "type": "quantitative"
        }
      },
      "name": "view_465e291a7facf71e_0",
      "title": "IMDB vs Rotten Tomatoes Ratings",
      "transform": [
        {
          "filter": "(datum.IMDB_Rating !== null)"
        },
        {
          "filter": "(datum.Rotten_Tomatoes_Rating !== null)"
        }
      ]
    },
    {
      "hconcat": [
        {
          "mark": {
            "type": "bar"
          },
          "encoding": {
            "x": {
              "field": "Major_Genre",
              "title": "Genre",
              "type": "nominal"
            },
            "y": {
              "aggregate": "count",
              "title": "Count",
              "type": "quantitative"
            }
          },
          "title": "Top 8 Genres (brushed)",
          "transform": [
            {
              "filter": "(datum.IMDB_Rating !== null)"
            },
            {
              "filter": {
                "param": "brush"
              }
            },
            {
              "aggregate": [
                {
                  "op": "count",
                  "as": "count"
                }
              ],
              "groupby": [
                "Major_Genre"
              ]
            },
            {
              "window": [
                {
                  "op": "rank",
                  "field": "count",
                  "as": "rank"
                }
              ],
              "sort": [
                {
                  "field": "count",
                  "order": "descending"
                }
              ]
            },
            {
              "filter": "(datum.rank <= 8)"
            }
          ]
        },
        {
          "mark": {
            "type": "bar"
          },
          "encoding": {
            "x": {
              "bin": {
                "maxbins": 20
              },
              "field": "IMDB_Rating",
              "title": "IMDB Rating",
              "type": "quantitative"
            },
            "y": {
              "aggregate": "count",
              "title": "Count",
              "type": "quantitative"
            }
          },
          "title": "IMDB Rating Distribution (brushed)",
          "transform": [
            {
              "filter": "(datum.IMDB_Rating !== null)"
            },
            {
              "filter": {
                "param": "brush"
              }
            }
          ]
        }
      ]
    }
  ],
  "data": {
    "url": "https://cdn.jsdelivr.net/npm/vega-datasets@v1.29.0/data/movies.json"
  },
  "params": [
    {
      "name": "brush",
      "select": {
        "type": "interval"
      },
      "views": [
        "view_465e291a7facf71e_0"
      ]
    }
  ],
  "resolve": {
    "scale": {
      "color": "independent"
    }
  },
  "$schema": "https://vega.github.io/schema/vega-lite/v6.4.1.json"
}
